const e={configTemplates:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Blocs de configuration et macros Klipper prêts à coller — séquences de démarrage, gestion du filament, input shaping, maillage du plateau et plus encore. Copiez-en un et déposez-le dans votre printer.cfg (l'éditeur de configuration est un bon endroit pour le coller)."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Aide"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"À propos des modèles de configuration"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Fermer"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"Comment l'utiliser"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"Filtrez par catégorie pour trouver une macro ou un bloc de configuration."}},{t:0,b:{t:2,i:[{t:3}],s:"Lisez la description et les sections dont elle a besoin."}},{t:0,b:{t:2,i:[{t:3}],s:"Copiez le modèle, collez-le dans votre configuration et ajustez les valeurs."}}],topics:{what:{title:{t:0,b:{t:2,i:[{t:3}],s:"Ce que c'est"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Un ensemble sélectionné de blocs Klipper courants : des gcode_macros (PRINT_START, PAUSE/RESUME, chargement/déchargement du filament, M600) et des sections de configuration ([input_shaper], [bed_mesh], [firmware_retraction], …). Ce sont des points de départ — lisez chacun d'eux et adaptez-le à votre machine."}}},insert:{title:{t:0,b:{t:2,i:[{t:3}],s:"Insérer un modèle"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Copiez un modèle, puis collez-le dans votre printer.cfg — la vue brute de l'éditeur de configuration est un endroit pratique. Après l'enregistrement, un redémarrage du firmware l'applique. Vérifiez toujours les valeurs au préalable ; les valeurs par défaut ici sont raisonnables mais ne sont pas réglées pour votre imprimante."}}},sections:{title:{t:0,b:{t:2,i:[{t:3}],s:"Sections requises"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Chaque modèle indique les sections de configuration qu'il définit ou dont il dépend. Si une section existe déjà dans votre configuration, fusionnez les clés plutôt que de coller un doublon (une section en double est rejetée au démarrage)."}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Glossaire"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{template:{term:{t:0,b:{t:2,i:[{t:3}],s:"Modèle"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Un extrait prêt à coller de configuration Klipper ou de G-code de macro que vous copiez dans printer.cfg."}}},macro:{term:{t:0,b:{t:2,i:[{t:3}],s:"gcode_macro"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Une commande nommée que vous définissez dans la configuration (par ex. PRINT_START) et qui exécute une séquence de G-code."}}},section:{term:{t:0,b:{t:2,i:[{t:3}],s:"Section"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Un bloc de configuration entre [crochets], par ex. [bed_mesh] — l'unité dans laquelle la configuration Klipper est regroupée."}}}}},category:{label:{t:0,b:{t:2,i:[{t:3}],s:"Catégorie"}},all:{t:0,b:{t:2,i:[{t:3}],s:"Toutes les catégories"}}},template:{copy:{t:0,b:{t:2,i:[{t:3}],s:"Copier"}},copied:{t:0,b:{t:2,i:[{t:3}],s:"Copié !"}},requires:{t:0,b:{t:2,i:[{t:3,v:"Sections : "},{t:4,k:"sections"}]}},requiresNone:{t:0,b:{t:2,i:[{t:3}],s:"—"}}},count:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" modèles"}]}},states:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Chargement des modèles…"}},error:{t:0,b:{t:2,i:[{t:3}],s:"Impossible de charger les modèles."}},empty:{t:0,b:{t:2,i:[{t:3}],s:"Aucun modèle dans cette catégorie."}},retry:{t:0,b:{t:2,i:[{t:3}],s:"Réessayer"}}}}};export{e as default};
